// Create a variable called 'name' with 'Aysel'
var name = 'Aysel';
console.log(name); // Output: Aysel

// Change the variable's content
name = 'Kamran';
console.log(name); // Output: Kamran

// Hoisting example
console.log(toy); // Output: undefined (no error!)
var toy = 'robot';
console.log(toy); // Output: robot

// Function scope example
function test() {
  var color = 'blue';
  console.log(color); // Output: blue
}
test();
// console.log(color); // Error: color is not defined, because it’s not accessible outside the function

// You can redeclare with var
var gadget = 'phone';
var gadget = 'earphones';
console.log(gadget); // Output: earphones

// You can’t redeclare with let
let drink = 'cola';
// let drink = 'water'; // Error: drink has already been declared

// You can’t change const’s value
const name = 'Kamran';
// name = 'Murad'; // Error: Assignment to constant variable

// Real-life example
var bag = 'laptop';
console.log(bag); // Output: laptop

// Change the bag’s content
bag = 'book';
console.log(bag); // Output: book

// Redeclare it, no problem
var bag = 'pen';
console.log(bag); // Output: pen

