// Меняем содержимое переменной
name = 'Кямран';
console.log(name); // Вывод: Кямран

// Пример hoisting
console.log(toy); // Вывод: undefined (без ошибки!)
var toy = 'робот';
console.log(toy); // Вывод: робот

// Пример области видимости функции
function test() {
  var color = 'синий';
  console.log(color); // Вывод: синий
}
test();
// console.log(color); // Ошибка: color не определён, так как недоступен вне функции

// Можно повторно объявить с var
var gadget = 'телефон';
var gadget = 'наушники';
console.log(gadget); // Вывод: наушники

// Нельзя повторно объявить с let
let drink = 'кола';
// let drink = 'вода'; // Ошибка: drink уже объявлен

// Нельзя изменить значение const
const name = 'Кямран';
// name = 'Мурад'; // Ошибка: Присвоение константе

// Пример из реальной жизни
var bag = 'laptop';
console.log(bag); // Вывод: laptop

// Меняю содержимое сумки
bag = 'book';
console.log(bag); // Вывод: book

// Повторно объявляю, нет проблем
var bag = 'pen';
console.log(bag); // Вывод: pen

